import { productSchema } from '@/lib/validations';
import { zodResolver } from '@hookform/resolvers/zod';
import { useRouter } from 'next/navigation';
import React from 'react';
import { useForm } from 'react-hook-form';
import z from 'zod';
import { Form, FormControl, FormDescription, FormField, FormItem, FormLabel } from '@/components/ui/form';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';

interface Props extends Partial<Product> { }

const ProductForm = ({ ...products }: Props) => {
    const router = useRouter();
    const form = useForm<z.infer<typeof productSchema>>({
        resolver: zodResolver(productSchema),
        defaultValues: {
            productName: "",
            productBarcode: "",
            quantity: 1,
            price: 1,
        },
    });
    const onSubmit = async (values: z.infer<typeof productSchema>) => {
        // const result = await addProducts(values);

    }
    return (
        <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)} className='m-10 p-10 space-y-8' method='POST'>
                <FormField
                    control={form.control}
                    name='productName'
                    render={({ field }) => (
                        <FormItem>
                            <FormLabel>Product Name</FormLabel>
                            <FormControl>
                                <Input placeholder="Product Name" {...field} />
                            </FormControl>
                            {/* <FormDescription></FormDescription> */}
                        </FormItem>
                    )}
                >
                </FormField>
            </form>
            <Button type='submit' className='cursor-pointer'>Add product</Button>
        </Form>
    )
}

export default ProductForm